challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The HSS (pyhss) is unresponsive or severely degraded, causing Diameter Cx timeouts at the I-CSCF and high response latency at the S-CSCF. This is disrupting IMS registration and call setup procedures.",
      "primary_suspect_nf": "pyhss",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from 'icscf' to 'pyhss' IP address",
          "expected_if_hypothesis_holds": "High RTT (>1000ms) or 100% packet loss, indicating a network partition or that the pyhss container is too overloaded to respond to ICMP.",
          "falsifying_observation": "Low RTT (<10ms) and 0% packet loss. This proves the network path is healthy and the container is responsive at the network layer."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from 'scscf' to 'pyhss' IP address",
          "expected_if_hypothesis_holds": "Similar high RTT or packet loss as seen from the I-CSCF, confirming pyhss or its direct network access is the issue.",
          "falsifying_observation": "Low RTT. If the I-CSCF->HSS ping is bad but this one is good, it points to a problem specific to the I-CSCF or its path, not the HSS itself, thus falsifying the hypothesis."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container: 'pyhss'",
          "expected_if_hypothesis_holds": "The pyHSS process is not listening on the Diameter port (TCP 3868), indicating a crash, hang, or startup failure.",
          "falsifying_observation": "The process is listening on TCP port 3868. This would prove the HSS application process is up and its listening socket is open, making a simple crash unlikely."
        }
      ],
      "notes": "This plan tests for network-level unreachability and process liveness of the HSS. The hypothesis is anchored to the 'ims_registration' and 'diameter_cx_authentication' flows, where I-CSCF and S-CSCF query the HSS."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "Severe packet loss is occurring on the VoNR media plane, as directly measured by RTPEngine. The loss is happening either within RTPEngine itself or on the N3/N6 path at the UPF.",
      "primary_suspect_nf": "rtpengine",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds: 30",
          "expected_if_hypothesis_holds": "Gauges for 'rtpengine' will show high `rtp_packet_loss_percent` (>5%) and a correspondingly low `mos_score` (<3.0) for active VoNR call flows.",
          "falsifying_observation": "Low packet loss (<1%) and high MOS scores (>4.0). This would directly contradict the core evidence for the hypothesis."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from 'upf' to 'rtpengine' IP address",
          "expected_if_hypothesis_holds": "High RTT or significant packet loss, suggesting the N6 network path between the UPF and RTPEngine is degraded.",
          "falsifying_observation": "Low RTT and 0% packet loss. This would indicate the network path itself is healthy, pointing towards packet loss occurring *inside* one of the NFs rather than between them."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from 'rtpengine' to 'upf' IP address",
          "expected_if_hypothesis_holds": "Similar high RTT or packet loss (triangulation probe). This would confirm a bidirectional network issue on the N6 path is the likely cause of loss.",
          "falsifying_observation": "Low RTT. If the UPF->rtpengine ping is bad but this reverse-path probe is good, it suggests an asymmetric routing/firewall issue or a problem specific to the UPF's egress path, rather than a general path failure."
        }
      ],
      "notes": "This plan focuses on quantifying the media plane degradation and isolating the location of packet loss (i.e., on the network path vs. inside an NF). It relates to the 'vonr_call_setup' flow, step 12, where RTP media is active."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "The UPF is experiencing a data plane forwarding issue, dropping a significant percentage of GTP-U packets. This would explain both the anomalous per-UE GTP metrics and the downstream packet loss reported by RTPEngine.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds: 30",
          "expected_if_hypothesis_holds": "The UPF's per-UE GTP metrics will show a significant discrepancy between packets/bytes received on the N3 interface and packets/bytes sent on the N6 interface.",
          "falsifying_observation": "Ingress and egress GTP packet/byte counts at the UPF are balanced for all active PDU sessions. This would prove the UPF is forwarding traffic correctly."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "Get all metrics and filter for gnb.gtp.tx_pkts and upf.n3.rx_pkts",
          "expected_if_hypothesis_holds": "The number of GTP-U packets sent from the gNB (e.g., `gnb.gtp.tx_pkts`) is significantly higher than the number of packets received by the UPF on its N3 interface (`upf.n3.rx_pkts`).",
          "falsifying_observation": "The gNB's transmitted packet count closely matches the UPF's received packet count on the N3 interface. This proves packets aren't being dropped on the N3 link *before* the UPF, contradicting the 'activity-vs-drops' premise."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from 'nr_gnb' to 'rtpengine' IP address",
          "expected_if_hypothesis_holds": "High packet loss. This end-to-end check from the RAN to the IMS media anchor traverses the entire data path, including the UPF. Loss here would be consistent with a faulty UPF.",
          "falsifying_observation": "Low RTT and 0% packet loss. This would indicate the full data path from RAN, through the UPF, to the media anchor is healthy, strongly falsifying the hypothesis that the UPF is dropping packets."
        }
      ],
      "notes": "This plan tries to confirm packet loss at the UPF by comparing ingress/egress counters (from `get_dp_quality_gauges`) and checking upstream delivery from the gNB. The end-to-end path check serves as a comprehensive test of the entire user plane."
    }
  ]
}

